#include <stdio.h>
#include <string.h>

int isPrime(int n) {
    if (n <= 1) return 0;
    if (n <= 3) return 1;
    if (n % 2 == 0 || n % 3 == 0) return 0;
    for (int i = 5; i * i <= n; i += 6) {
        if (n % i == 0 || n % (i + 2) == 0) return 0;
    }
    return 1;
}

int main() {
    int T, X, Y, A, B, C;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &X, &Y);
        for (A = 2; A < 230; A++) {
            if (!isPrime(A)) continue;
            for (B = 2; B < 230; B++) {
                if (!isPrime(B)) continue;
                for (C = 2; C < 230; C++) {
                    if (!isPrime(C)) continue;
                    if ((A ^ B) == X && (B ^ C) == Y && ((A ^ B) % 2 == 1 || (B ^ C) % 2 == 1 || (C ^ A) % 2 == 1)) {
                        printf("%d %d %d\n", A, B, C);
                        goto next_test_case;
                    }
                }
            }
        }
        next_test_case:
        continue;
    }
    return 0;
}

